    public void add(SessionLocal session, Row row) {
        TransactionMap<Spatial, Value> map = getMap(session);
        SpatialKey key = getKey(row);

        if (key.isNull()) {
            return;
        }

        if (uniqueColumnColumn > 0) {
            // this will detect committed entries only
            RTreeCursor<VersionedValue<Value>> cursor = spatialMap.findContainedKeys(key);
            Iterator<Spatial> it = new SpatialKeyIterator(map, cursor, false);
            while (it.hasNext()) {
                Spatial k = it.next();
                if (k.equalsIgnoringId(key)) {
                    throw getDuplicateKeyException(key.toString());
                }
            }
        }
        try {
            map.put(key, ValueNull.INSTANCE);
        } catch (MVStoreException e) {
            throw mvTable.convertException(e);
        }
        if (uniqueColumnColumn > 0) {
            // check if there is another (uncommitted) entry
            RTreeCursor<VersionedValue<Value>> cursor = spatialMap.findContainedKeys(key);
            Iterator<Spatial> it = new SpatialKeyIterator(map, cursor, true);
            while (it.hasNext()) {
                Spatial k = it.next();
                if (k.equalsIgnoringId(key)) {
                    if (map.isSameTransaction(k)) {
                        continue;
                    }
                    map.remove(key);
                    if (map.getImmediate(k) != null) {
                        // committed
                        throw getDuplicateKeyException(k.toString());
                    }
                    throw DbException.get(ErrorCode.CONCURRENT_UPDATE_1, table.getName());
                }
            }
        }
    }

    public void add(SessionLocal session, Row row) {
        TransactionMap<SearchRow,Value> map = getMap(session);
        SearchRow key = convertToKey(row, null);
        boolean checkRequired = uniqueColumnColumn > 0 && !mayHaveNullDuplicates(row);
        if (checkRequired) {
            boolean repeatableRead = !session.getTransaction().allowNonRepeatableRead();
            checkUnique(repeatableRead, map, row, Long.MIN_VALUE);
        }

        try {
            map.put(key, ValueNull.INSTANCE);
        } catch (MVStoreException e) {
            throw mvTable.convertException(e);
        }

        if (checkRequired) {
            checkUnique(false, map, row, row.getKey());
        }
    }

